function renderPastPaper(subject, year) {
    const data = window['PAST_PAPERS_' + subject.toUpperCase()];
    if (!data || !data[year]) {
        document.getElementById('paperContent').innerHTML = '<p>No data available for ' + year + '</p>';
        return;
    }
    const info = data[year];
    let html = '<div class="card"><h2>' + subject.charAt(0).toUpperCase() + subject.slice(1) + ' ' + year + ' — Past Paper Review</h2></div>';
    const paperNames = Object.keys(info.papers);
    if (paperNames.length > 0) {
        paperNames.forEach(function(pname) {
            const label = pname.replace('paper1','Paper 1').replace('paper2','Paper 2')
                .replace('paper','Exam Paper').replace('written','Written Exam').replace('listening','Listening Test')
                .replace('sectionsAB','Sections A & B').replace('sectionC','Section C');
            html += '<div class="card"><h3>' + label + '</h3>';
            html += '<pre style="white-space:pre-wrap;font-family:inherit;font-size:0.9rem;color:var(--text-light);line-height:1.7;max-height:500px;overflow-y:auto;">';
            html += info.papers[pname];
            html += '</pre></div>';
        });
    }
    if (info.marking) {
        html += '<div class="card"><h3>Marking Scheme</h3>';
        html += '<pre style="white-space:pre-wrap;font-family:inherit;font-size:0.9rem;color:var(--text-light);line-height:1.7;max-height:500px;overflow-y:auto;">';
        html += info.marking;
        html += '</pre></div>';
    }
    document.getElementById('paperContent').innerHTML = html;
}